"use client";

import { signOut, useSession } from "next-auth/react";
import Image from "next/image";
import { useRouter } from "next/navigation";
import { useState, type FC } from "react";

import { useProfile } from "@/entities/profile";
import { APP_ROUTES } from "@/shared/config/app-routes";
import { getFullName } from "@/shared/lib/utils/get-full-name";
import { useSignedFileUrl } from "@/shared/api/query-hooks/use-file-upload";
import { UserRole } from "@/shared/types";
import { Popover, PopoverContent, PopoverTrigger } from "@/shared/ui/popover";
import { Separator } from "@/shared/ui/separator";
import Link from "next/link";

export const ProfilePopover: FC = () => {
  const router = useRouter();
  const { data: session } = useSession();
  const [open, setOpen] = useState(false);

  const { data: liveProfile } = useProfile();
  const profile = liveProfile ?? session?.user?.profile;
  const photoFileId = liveProfile?.photoFileId ?? null;
  const { data: photoData } = useSignedFileUrl(photoFileId ?? "", !!photoFileId);

  const isAdmin = !!profile?.admin;
  const selectedRole = profile?.selectedRole;

  const handleLogout = async () => {
    await signOut({ redirect: false });
    router.push(APP_ROUTES.AUTH.SIGN_IN);
    router.refresh();
  };

  return (
    <Popover open={open} onOpenChange={setOpen}>
      <PopoverTrigger asChild>
        <button
          type="button"
          className="flex size-10 items-center justify-center overflow-hidden rounded-full transition-opacity hover:opacity-70"
          aria-label="Profile"
        >
          {photoData?.url ? (
            <Image
              src={photoData.url}
              alt="Profile"
              width={40}
              height={40}
              className="h-full w-full object-cover"
            />
          ) : (
            <Image
              src="/mock-images/user-circle.svg"
              alt="Profile icon"
              width={40}
              height={40}
            />
          )}
        </button>
      </PopoverTrigger>
      <PopoverContent
        align="end"
        sideOffset={8}
        className="z-[100] w-[440px] rounded-xl border border-border bg-white p-5 shadow-[0px_0px_8px_0px_rgba(0,0,0,0.08)]"
      >
        <div className="flex flex-col gap-4">
          <Link
            href={APP_ROUTES.PROFILE}
            onClick={() => setOpen(false)}
            className="flex items-center gap-3 rounded-lg border border-transparent p-3 transition-all hover:border-primary hover:bg-secondary/10"
          >
            <div className="flex size-[50px] shrink-0 items-center justify-center overflow-hidden rounded-full bg-secondary/20">
              {photoData?.url ? (
                <Image
                  src={photoData.url}
                  alt="Profile"
                  width={50}
                  height={50}
                  className="h-full w-full object-cover"
                />
              ) : (
                <Image
                  src="/mock-images/user-circle.svg"
                  alt="Profile icon"
                  width={32}
                  height={32}
                />
              )}
            </div>
            <div className="flex flex-1 flex-col gap-1">
              <h3 className="font-bold font-serif text-foreground text-lg leading-[1.199em]">
                {profile ? (getFullName(profile) || "User") : "User"}
              </h3>
              <span className="font-serif text-primary text-sm underline">
                View{" "}
                {profile?.selectedRole === UserRole.SUPER_ADMIN ||
                profile?.selectedRole === UserRole.ADMIN
                  ? "Dashboard"
                  : "Profile"}{" "}
                →
              </span>
            </div>
          </Link>

          <Separator className="h-px w-full bg-border" />

          <div className="flex flex-col gap-2">
            <span className="font-serif text-foreground text-sm">
              {isAdmin ? "Admin" : selectedRole || "User"}
            </span>
            <span className="truncate font-serif text-foreground text-sm">
              {profile?.email || ""}
            </span>
          </div>

          <button
            type="button"
            onClick={handleLogout}
            className="w-full text-left font-serif text-base text-foreground transition-opacity hover:opacity-70"
          >
            Logout
          </button>
        </div>
      </PopoverContent>
    </Popover>
  );
};

"use client";

import {
  BellIcon,
  CircleUserRound,
  InboxIcon,
  LogOutIcon,
  ScrollTextIcon,
} from "lucide-react";
import { signOut, useSession } from "next-auth/react";
import Image from "next/image";
import Link from "next/link";
import { usePathname, useRouter } from "next/navigation";
import { type FC, useEffect, useState } from "react";

import { useProfile } from "@/entities/profile";
import { useSignedFileUrl } from "@/shared/api/query-hooks/use-file-upload";
import { APP_ROUTES } from "@/shared/config/app-routes";
import { cn } from "@/shared/lib/ui/cn";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/shared/ui/dropdown-menu";
import { NotificationBadge } from "@/shared/ui/shadcn/badge";
import {
  NavigationMenu,
  NavigationMenuContent,
  NavigationMenuItem,
  NavigationMenuLink,
  NavigationMenuList,
  NavigationMenuTrigger,
} from "@/shared/ui/shadcn/navigation-menu";
import { MobileMenu } from "./mobile-menu";

const ABOUT_LINKS = [
  { title: "About LuxFlow", href: APP_ROUTES.APP.ABOUT },
  { title: "Our Method", href: APP_ROUTES.SERVICES.DIRECT_SALE }, // Используем константу из роутов
  { title: "Contact Us", href: APP_ROUTES.APP.CONTACT },
  { title: "Support", href: APP_ROUTES.SUPPORT },
  { title: "FAQs", href: APP_ROUTES.APP.FAQ },
];

const NAV_LINKS = [
  { title: "Home", href: "/" },
  { title: "Buyback", href: "/services/buyback" },
  { title: "Permanent Sale", href: "/services/permanent-sale" },
];

interface HeaderProps {
  className?: string;
}

export const Header: FC<HeaderProps> = ({ className }) => {
  const { status } = useSession();
  const isAuthenticated = status === "authenticated";
  const router = useRouter();
  const pathname = usePathname();

  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 60);
    onScroll();
    window.addEventListener("scroll", onScroll, { passive: true });
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  const isLanding = pathname === "/";
  const isTransparent = isLanding && !scrolled;

  const { data: profile } = useProfile();
  const photoFileId = profile?.photoFileId ?? null;
  const { data: photoData } = useSignedFileUrl(
    photoFileId ?? "",
    !!photoFileId,
  );
  const avatarSrc = photoData?.url ?? null;

  const handleLogout = async () => {
    await signOut({ redirect: false });
    router.push(APP_ROUTES.AUTH.SIGN_IN);
    router.refresh();
  };

  const whatsappUrl = "https://wa.me/???";

  return (
    <header
      className={cn(
        "new-design fixed top-0 right-0 left-0 z-50 w-full font-[500] font-new-sans text-sm transition-colors duration-300",
        isTransparent
          ? "border-background border-b-[0.5px] bg-transparent text-background"
          : "border-border border-b bg-background",
        className,
      )}
    >
      <div className="mx-auto max-w-[1720px] px-4 py-3 min-[1172px]:px-10">
        <div className="hidden grid-cols-3 items-center lg:grid">
          <nav className="flex items-center gap-4 xl:gap-6">
            {NAV_LINKS.map((link) => (
              <Link
                className="whitespace-nowrap transition-opacity hover:opacity-60"
                href={link.href}
                key={link.href}
              >
                {link.title}
              </Link>
            ))}

            {isAuthenticated && (
              <Link
                className="whitespace-nowrap transition-opacity hover:opacity-60"
                href="/my-offers"
              >
                My Offers
              </Link>
            )}

            <NavigationMenu>
              <NavigationMenuList>
                <NavigationMenuItem>
                  <NavigationMenuTrigger className="h-auto p-0 font-[500] font-new-sans text-sm hover:bg-transparent hover:opacity-60 focus:bg-transparent">
                    About
                  </NavigationMenuTrigger>
                  <NavigationMenuContent>
                    <ul className="flex w-[200px] flex-col gap-1 rounded-md border border-border bg-background p-2">
                      {ABOUT_LINKS.map((link) => (
                        <li key={link.href}>
                          <NavigationMenuLink asChild>
                            <Link
                              className="block rounded-sm px-3 py-2 font-normal text-sm transition-colors hover:bg-transparent hover:text-foreground"
                              href={link.href}
                            >
                              {link.title}
                            </Link>
                          </NavigationMenuLink>
                        </li>
                      ))}
                    </ul>
                  </NavigationMenuContent>
                </NavigationMenuItem>
              </NavigationMenuList>
            </NavigationMenu>
          </nav>

          <div className="flex justify-center">
            <Logo className="h-8 w-48" invert={isTransparent} />
          </div>

          <div className="flex items-center justify-end gap-3 xl:gap-5">
            <a
              className="flex items-center gap-2 hover:opacity-60"
              href={whatsappUrl}
              rel="noopener noreferrer"
              target="_blank"
            >
              <span className="hidden xl:inline">Text Us</span>
              <Image
                alt="WhatsApp"
                height={20}
                src="/new-design-images/icons/whatsup.svg"
                width={20}
              />
            </a>

            <Link
              className="whitespace-nowrap rounded bg-[#000E65] px-4 py-2 font-medium text-[12px] text-white transition-colors hover:bg-blue-900"
              href={APP_ROUTES.BUYBACK_REQUESTS.CREATE}
            >
              Start with a Quote
            </Link>

            {isAuthenticated ? (
              <div className="flex items-center gap-4">
                <NotificationBadge className="cursor-pointer">
                  <BellIcon
                    aria-label="Notifications"
                    className={isTransparent ? "text-white" : "text-foreground"}
                    size={24}
                  />
                </NotificationBadge>
                <div
                  className={cn(
                    "h-8 w-[1px]",
                    isTransparent ? "bg-white/30" : "bg-[#D6D3D1]",
                  )}
                />
                <DropdownMenu>
                  <DropdownMenuTrigger asChild>
                    <button
                      aria-label="User menu"
                      className="cursor-pointer overflow-hidden rounded-[4px] border border-transparent transition-colors hover:border-border focus:outline-none"
                      type="button"
                    >
                      <Image
                        alt="User Profile"
                        className="object-cover"
                        height={36}
                        src={
                          avatarSrc ?? "/new-design-images/avatar-example.png"
                        }
                        width={36}
                      />
                    </button>
                  </DropdownMenuTrigger>
                  <DropdownMenuContent
                    align="end"
                    className="w-[220px] rounded-xl border border-[#D6D3D1] bg-[#F5F3EF] p-1 shadow-[0px_4px_16px_rgba(0,0,0,0.08)]"
                    sideOffset={8}
                  >
                    <DropdownMenuItem asChild>
                      <Link
                        className="flex cursor-pointer items-center gap-3 rounded-lg px-3 py-2.5 font-new-sans text-[#44403C] text-sm hover:bg-[#EDE9E3] focus:bg-[#EDE9E3]"
                        href={APP_ROUTES.PROFILE}
                      >
                        <CircleUserRound
                          className="shrink-0 text-[#44403C]"
                          size={16}
                        />
                        Profile Settings
                      </Link>
                    </DropdownMenuItem>
                    <DropdownMenuItem asChild>
                      <Link
                        className="flex cursor-pointer items-center gap-3 rounded-lg px-3 py-2.5 font-new-sans text-[#44403C] text-sm hover:bg-[#EDE9E3] focus:bg-[#EDE9E3]"
                        href={APP_ROUTES.WALLET.ROOT}
                      >
                        <InboxIcon
                          className="shrink-0 text-[#44403C]"
                          size={16}
                        />
                        Accounts & Wallets
                      </Link>
                    </DropdownMenuItem>
                    <DropdownMenuItem asChild>
                      <Link
                        className="flex cursor-pointer items-center gap-3 rounded-lg px-3 py-2.5 font-new-sans text-[#44403C] text-sm hover:bg-[#EDE9E3] focus:bg-[#EDE9E3]"
                        href={APP_ROUTES.WALLET.PAYMENT_HISTORY}
                      >
                        <ScrollTextIcon
                          className="shrink-0 text-[#44403C]"
                          size={16}
                        />
                        Transaction History
                      </Link>
                    </DropdownMenuItem>
                    <DropdownMenuSeparator className="my-1 bg-[#D6D3D1]" />
                    <DropdownMenuItem
                      className="flex cursor-pointer items-center gap-3 rounded-lg px-3 py-2.5 font-new-sans text-[#44403C] text-sm hover:bg-[#EDE9E3] focus:bg-[#EDE9E3]"
                      onClick={handleLogout}
                    >
                      <LogOutIcon
                        className="shrink-0 text-[#44403C]"
                        size={16}
                      />
                      Logout
                    </DropdownMenuItem>
                  </DropdownMenuContent>
                </DropdownMenu>
              </div>
            ) : (
              <div className="flex items-center gap-3">
                <Link
                  className="hover:opacity-60"
                  href={APP_ROUTES.AUTH.SIGN_IN}
                >
                  Login
                </Link>
                <div className="h-4 w-[1px] bg-black/10" />
                <Link
                  className="hover:opacity-60"
                  href={APP_ROUTES.AUTH.REGISTER}
                >
                  Register
                </Link>
              </div>
            )}
          </div>
        </div>

        {/* --- Mobile Version --- */}
        <div className="flex items-center justify-between lg:hidden">
          <MobileMenu isAuthenticated={isAuthenticated} />

          <Logo className="h-6 w-32" invert={isTransparent} />

          <div className="flex items-center gap-3">
            <a
              aria-label="Contact on WhatsApp"
              className="hover:opacity-60"
              href={whatsappUrl}
              rel="noopener noreferrer"
              target="_blank"
            >
              <Image
                alt=""
                height={22}
                src="/new-design-images/icons/whatsup.svg"
                width={22}
              />
            </a>
            {isAuthenticated ? (
              <NotificationBadge>
                <BellIcon aria-label="Notifications" size={22} />
              </NotificationBadge>
            ) : (
              <Link className="text-md" href={APP_ROUTES.AUTH.SIGN_IN}>
                Login
              </Link>
            )}
          </div>
        </div>
      </div>
    </header>
  );
};

const Logo = ({
  className,
  invert,
}: {
  className: string;
  invert?: boolean;
}) => (
  <Link className={cn("relative", className)} href="/">
    <Image
      alt="LUXFLOW"
      className={cn(
        "object-contain transition-[filter] duration-300",
        invert && "brightness-0 invert",
      )}
      fill
      priority
      src="/new-design-images/header-logo.svg"
    />
  </Link>
);

