287	function NotificationsCard() {
288	  const { data: userSettings, isLoading } = useUserSettings();
289	  const updateMutation = useUpdateUserSettings();
290	  const debounceRef = useRef<NodeJS.Timeout | null>(null);
291	
292	  const notif = userSettings?.[UserSetting.Notifications] ?? null;
293	
294	  const handleToggle = useCallback(
295	    (field: keyof UserNotificationsSetting, value: boolean) => {
296	      if (!notif) return;
297	      if (debounceRef.current) clearTimeout(debounceRef.current);
298	      debounceRef.current = setTimeout(() => {
299	        updateMutation.mutate(
300	          { [UserSetting.Notifications]: { ...notif, [field]: value } },
301	          {
302	            onSuccess: () => toast.success("Settings updated"),
303	            onError: () => toast.error("Failed to update settings"),
304	          }
305	        );
306	      }, 300);
307	    },
308	    [notif, updateMutation]
309	  );
310	
311	  const items: {
312	    field: keyof UserNotificationsSetting;
313	    icon: ReactNode;
314	    title: string;
315	    description: string;
316	  }[] = [
317	    {
318	      field: "general",
319	      icon: <BellRing className="h-5 w-5 shrink-0 text-[#78716C]" />,
320	      title: "General Notification",
321	      description: "Enable all Notification for Updates and Alerts",
322	    },
323	    {
324	      field: "buyback",
325	      icon: <RefreshCw className="h-5 w-5 shrink-0 text-[#78716C]" />,
326	      title: "BuyBack Notifications",
327	      description: "Alerts for BuyBack Repayment, due dates etc",
328	    },
329	    {
330	      field: "accountSecurity",
