333	      description: "Notifications for login attempts, password changes",
334	    },
335	  ];
336	
337	  return (
338	    <SettingsCard>
339	      <CardHeader title="Notification settings" />
340	
341	      <div className="flex flex-col divide-y divide-[#E7E5E4]">
342	        {isLoading
343	          ? [1, 2, 3].map((i) => (
344	              <div
345	                className="h-14 animate-pulse bg-[#F5F3EF] first:rounded-t-xl last:rounded-b-xl"
346	                key={i}
347	              />
348	            ))
349	          : items.map(({ field, icon, title, description }) => (
350	              <div
351	                className="flex items-center gap-4 py-3 first:pt-0 last:pb-0"
352	                key={field}
353	              >
354	                {icon}
355	                <div className="flex flex-1 flex-col leading-[150%] tracking-[-1%]">
356	                  <span className="font-medium font-new-sans text-sm">
357	                    {title}
358	                  </span>
359	                  <span className="font-new-sans text-sm">{description}</span>
360	                </div>
361	                <Switch
362	                  checked={notif?.[field] ?? false}
363	                  disabled={!notif}
364	                  onCheckedChange={(value) => handleToggle(field, value)}
365	                />
366	              </div>
367	            ))}
368	      </div>
369	    </SettingsCard>
370	  );
371	}
