import Image from "next/image";
import type { FC } from "react";

import { cn } from "@/shared/lib/ui/cn";

interface UserAvatarProps {
  src?: string | null;
  firstName?: string | null;
  size?: number;
  className?: string;
}

export const UserAvatar: FC<UserAvatarProps> = ({
  src,
  firstName,
  size = 36,
  className,
}) => {
  if (src) {
    return (
      <Image
        alt="User avatar"
        className={cn("object-cover", className)}
        height={size}
        src={src}
        width={size}
      />
    );
  }

  const letter = firstName?.trim()?.[0]?.toUpperCase() ?? "?";

  return (
    <div
      className={cn(
        "flex items-center justify-center bg-[#000E65] font-medium font-new-sans text-white",
        className,
      )}
      style={{ width: size, height: size, fontSize: Math.round(size * 0.44) }}
    >
      {letter}
    </div>
  );
};

