function ProfilePictureCard({
  photoFileId,
  firstName,
}: {
  photoFileId: string | null;
  firstName: string;
}) {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const { mutate: updatePhoto, isPending: isUpdating } =
    useUpdateProfilePhoto();
  const { mutate: uploadFile, isPending: isUploading } = useFileUpload();
  const { data: photoData } = useSignedFileUrl(
    photoFileId ?? "",
    !!photoFileId
  );

  const isPending = isUploading || isUpdating;

  function handleReplaceClick() {
    fileInputRef.current?.click();
  }

  function handleFileChange(event: React.ChangeEvent<HTMLInputElement>) {
    const file = event.target.files?.[0];
    if (!file) return;

    uploadFile(
      {
        file,
        folder: S3_FOLDERS.STATIC,
        mime: file.type as MimeType,
        fileName: file.name,
      },
      {
        onSuccess: (uploaded) => {
          updatePhoto(
            { photoFileId: uploaded.fileId },
            {
              onSuccess: () => toast.success("Profile picture updated"),
              onError: () => toast.error("Failed to update profile picture"),
            }
          );
        },
      }
    );

    // Reset input so the same file can be re-selected
    event.target.value = "";
  }

  function handleDelete() {
    updatePhoto(
      { photoFileId: null },
      {
        onSuccess: () => toast.success("Profile picture removed"),
        onError: () => toast.error("Failed to remove profile picture"),
      }
    );
  }

  return (
    <SettingsCard>
      <CardHeader title="Profile Picture" />

      <div className="new-design flex items-center justify-between gap-3 rounded-lg bg-[#EDE9E3] p-4 text-center">
        {/* Avatar */}
        <div className="h-9 w-9 shrink-0 overflow-hidden bg-[#D6D3D1]">
          {photoData?.url ? (
            <Image
              alt="Profile picture"
              className="h-full w-full object-cover"
              height={36}
              src={photoData.url}
              width={36}
            />
          ) : (
            <div className="flex h-full items-center justify-center">
              <span className="flex items-center justify-center font-new-sans text-[#78716C] text-[9px]">
                No photo
              </span>
            </div>
          )}
        </div>

        {/* Actions */}
        <div className="flex items-center gap-4">
          <button
            className="rounded-lg border border-[#A8A29E] bg-[#F5F3EF] px-3 py-1.5 font-medium font-new-sans text-[#44403C] text-sm transition-colors hover:bg-[#EDE9E3]"
            disabled={isPending}
            onClick={handleReplaceClick}
            type="button"
          >
            {isUploading ? "Uploading…" : "Replace Profile Image"}
          </button>

          {photoFileId && (
            <button
              aria-label="Remove profile picture"
              className="transition-colors hover:text-[#44403C]"
              disabled={isPending}
              onClick={handleDelete}
              type="button"
            >
              <Trash2 className="h-5 w-5" />
            </button>
          )}
        </div>
      </div>

      <input
        accept={IMAGE_ACCEPT_TYPES}
        className="hidden"
        onChange={handleFileChange}
        ref={fileInputRef}
        type="file"
      />
    </SettingsCard>
  );
}

