function NotificationsCard() {
  const { data: userSettings, isLoading } = useUserSettings();
  const updateMutation = useUpdateUserSettings();
  const debounceRef = useRef<NodeJS.Timeout | null>(null);

  const notif = userSettings?.[UserSetting.Notifications] ?? null;

  const handleToggle = useCallback(
    (field: keyof UserNotificationsSetting, value: boolean) => {
      if (!notif) return;
      if (debounceRef.current) clearTimeout(debounceRef.current);
      debounceRef.current = setTimeout(() => {
        updateMutation.mutate(
          { [UserSetting.Notifications]: { ...notif, [field]: value } },
          {
            onSuccess: () => toast.success("Settings updated"),
            onError: () => toast.error("Failed to update settings"),
          }
        );
      }, 300);
    },
    [notif, updateMutation]
  );

  const items: {
    field: keyof UserNotificationsSetting;
    icon: ReactNode;
    title: string;
    description: string;
  }[] = [
    {
      field: "general",
      icon: <BellRing className="h-5 w-5 shrink-0 text-[#78716C]" />,
      title: "General Notification",
      description: "Enable all Notification for Updates and Alerts",
    },
    {
      field: "buyback",
      icon: <RefreshCw className="h-5 w-5 shrink-0 text-[#78716C]" />,
      title: "BuyBack Notifications",
      description: "Alerts for BuyBack Repayment, due dates etc",
    },
    {
      field: "accountSecurity",
      icon: <ShieldAlert className="h-5 w-5 shrink-0 text-[#78716C]" />,
      title: "Account Security Alerts",
      description: "Notifications for login attempts, password changes",
    },
  ];

  return (
    <SettingsCard>
      <CardHeader title="Notification settings" />

      <div className="flex flex-col divide-y divide-[#E7E5E4]">
        {isLoading
          ? [1, 2, 3].map((i) => (
              <div
                className="h-14 animate-pulse bg-[#F5F3EF] first:rounded-t-xl last:rounded-b-xl"
                key={i}
              />
            ))
          : items.map(({ field, icon, title, description }) => (
              <div
                className="flex items-center gap-4 py-3 first:pt-0 last:pb-0"
                key={field}
              >
                {icon}
                <div className="flex flex-1 flex-col leading-[150%] tracking-[-1%]">
                  <span className="font-medium font-new-sans text-sm">
                    {title}
                  </span>
                  <span className="font-new-sans text-sm">{description}</span>
                </div>
                <Switch
                  checked={notif?.[field] ?? false}
                  disabled={!notif}
                  onCheckedChange={(value) => handleToggle(field, value)}
                />
              </div>
            ))}
      </div>
    </SettingsCard>
  );
}

