"use client";

import { signOut, useSession } from "next-auth/react";
import Image from "next/image";
import { useRouter } from "next/navigation";
import { useState, type FC } from "react";

import { useProfile } from "@/entities/profile";
import { APP_ROUTES } from "@/shared/config/app-routes";
import { getFullName } from "@/shared/lib/utils/get-full-name";
import { useSignedFileUrl } from "@/shared/api/query-hooks/use-file-upload";
import { UserAvatar } from "@/shared/ui/user-avatar/user-avatar";
import { UserRole } from "@/shared/types";
import { Popover, PopoverContent, PopoverTrigger } from "@/shared/ui/popover";
import { Separator } from "@/shared/ui/separator";
import Link from "next/link";

export const ProfilePopover: FC = () => {
  const router = useRouter();
  const { data: session } = useSession();
  const [open, setOpen] = useState(false);

  const { data: liveProfile } = useProfile();
  const profile = liveProfile ?? session?.user?.profile;
  const photoFileId = liveProfile?.photoFileId ?? null;
  const { data: photoData } = useSignedFileUrl(photoFileId ?? "", !!photoFileId);

  const isAdmin = !!profile?.admin;
  const selectedRole = profile?.selectedRole;

  const handleLogout = async () => {
    await signOut({ redirect: false });
    router.push(APP_ROUTES.AUTH.SIGN_IN);
    router.refresh();
  };

  return (
    <Popover open={open} onOpenChange={setOpen}>
      <PopoverTrigger asChild>
        <button
          type="button"
          className="flex size-10 items-center justify-center overflow-hidden rounded-full transition-opacity hover:opacity-70"
          aria-label="Profile"
        >
          <UserAvatar
            firstName={profile?.firstName}
            size={40}
            src={photoData?.url}
          />
        </button>
      </PopoverTrigger>
      <PopoverContent
        align="end"
        sideOffset={8}
        className="z-[100] w-[440px] rounded-xl border border-border bg-white p-5 shadow-[0px_0px_8px_0px_rgba(0,0,0,0.08)]"
      >
        <div className="flex flex-col gap-4">
          <Link
            href={APP_ROUTES.PROFILE}
            onClick={() => setOpen(false)}
            className="flex items-center gap-3 rounded-lg border border-transparent p-3 transition-all hover:border-primary hover:bg-secondary/10"
          >
            <div className="flex size-[50px] shrink-0 items-center justify-center overflow-hidden rounded-full bg-secondary/20">
              <UserAvatar
                className="rounded-full"
                firstName={profile?.firstName}
                size={50}
                src={photoData?.url}
              />
            </div>
            <div className="flex flex-1 flex-col gap-1">
              <h3 className="font-bold font-serif text-foreground text-lg leading-[1.199em]">
                {profile ? (getFullName(profile) || "User") : "User"}
              </h3>
              <span className="font-serif text-primary text-sm underline">
                View{" "}
                {profile?.selectedRole === UserRole.SUPER_ADMIN ||
                profile?.selectedRole === UserRole.ADMIN
                  ? "Dashboard"
                  : "Profile"}{" "}
                →
              </span>
            </div>
          </Link>

          <Separator className="h-px w-full bg-border" />

          <div className="flex flex-col gap-2">
            <span className="font-serif text-foreground text-sm">
              {isAdmin ? "Admin" : selectedRole || "User"}
            </span>
            <span className="truncate font-serif text-foreground text-sm">
              {profile?.email || ""}
            </span>
          </div>

          <button
            type="button"
            onClick={handleLogout}
            className="w-full text-left font-serif text-base text-foreground transition-opacity hover:opacity-70"
          >
            Logout
          </button>
        </div>
      </PopoverContent>
    </Popover>
  );
};

